const rows = $input.all().map(item => item.json);
const webhookData = $('Webhook').first().json.body;

// Group readings by line
const lineGroups = {};
for (const row of rows) {
  if (!lineGroups[row.line_id]) {
    lineGroups[row.line_id] = [];
  }
  lineGroups[row.line_id].push(row);
}

const alerts = [];
const lineStatus = {};

for (const lineId in lineGroups) {
  const readings = lineGroups[lineId];

  if (readings.length < 3) continue;

  const severities = readings.map(r => r.status_severity);
  const mean = severities.reduce((sum, val) => sum + val, 0) / severities.length;
  const squaredDiffs = severities.map(val => Math.pow(val - mean, 2));
  const variance = squaredDiffs.reduce((sum, val) => sum + val, 0) / severities.length;
  const std = Math.sqrt(variance);

  const latest = readings[0];
  const currentValue = latest.status_severity;
  const zScore = std === 0 ? 0 : (mean - currentValue) / std;

  lineStatus[lineId] = {
    line_name: latest.line_name,
    current_severity: currentValue,
    status_description: latest.status_description,
    z_score: parseFloat(zScore.toFixed(2)),
    is_anomaly: zScore > 2,
    disruption_reason: latest.distruption_reason || null
  };

  if (zScore > 2) {
    alerts.push({
      line_id: lineId,
      line_name: latest.line_name,
      severity: currentValue,
      z_score: parseFloat(zScore.toFixed(2)),
      reason: latest.distruption_reason || 'Unknown'
    });
  }
}

return {
  user_id: webhookData.user_id,
  origin: webhookData.origin,
  destination: webhookData.destination,
  alerts: alerts,
  line_status: lineStatus,
  has_anomalies: alerts.length > 0,
  checked_at: new Date().toISOString()
};

const input = $input.first().json;
const now = new Date();

// Get all lines that need prediction (focus on lines with issues, but predict all for completeness)
const linesToPredict = Object.keys(input.line_status);

const predictions = [];
for (const lineId of linesToPredict) {
  const status = input.line_status[lineId];

  predictions.push({
    line_id: lineId,
    line_name: status.line_name,
    hour: now.getHours(),
    day_of_week: now.getDay(),
    status_severity: status.current_severity,
    is_anomaly: status.is_anomaly,
    z_score: status.z_score
  });
}

return {
  user_id: input.user_id,
  origin: input.origin,
  destination: input.destination,
  alerts: input.alerts,
  has_anomalies: input.has_anomalies,
  lines_to_predict: predictions,
  checked_at: input.checked_at
};

const items = $input.all().map(i => i.json);

// Build predictions map from LSTM results
const predictions = {};
for (const item of items) {
  if (item.line_id) {
    predictions[item.line_id] = {
      is_delayed: item.is_delayed,
      confidence: item.confidence,
      delay_probability: item.delay_probability || (item.is_delayed === 1 ? 0.8 : 0.2)
    };
  }
}

// We'll pass forward what we need - the next node will get user data from webhook
return {
  delay_predictions: predictions,
  predicted_at: new Date().toISOString()
};

const predictions = $input.first().json;
const webhookData = $('Webhook').first().json.body;
const agent1Data = $('Agent 1 - Z-Score Detection(Real Time monitor)').first().json;

return {
  user_id: webhookData.user_id,
  origin: webhookData.origin,
  destination: webhookData.destination,
  alerts: agent1Data.alerts,
