const stations = $input.all().map(i => i.json);
const connections = $('Get Connections').all().map(i => i.json);
const webhookData = $('Webhook').first().json.body;
const predictions = $('Agent 2 - Collect Predictions').first().json;

const origin = webhookData.origin;
const destination = webhookData.destination;
const delayPredictions = predictions.delay_predictions;

// Build graph
const graph = {};

for (const conn of connections) {
  const from = conn.from_station_id;
  const to = conn.to_station_id;
  let weight = conn.base_time_seconds || 120;

  const lineId = conn.line_id;
  if (delayPredictions[lineId]) {
    const prediction = delayPredictions[lineId];
    if (prediction.is_delayed === 1 || prediction.delay_probability > 0.3) {
      weight = weight * (1 + prediction.delay_probability);
    }
  }

  if (!graph[from]) graph[from] = [];
  if (!graph[to]) graph[to] = [];

  graph[from].push({ station: to, time: weight, line: lineId });
  graph[to].push({ station: from, time: weight, line: lineId });
}

// Dijkstra
const distances = {};
const previous = {};
const lineUsed = {};
const visited = new Set();
const queue = [];

for (const station of Object.keys(graph)) {
  distances[station] = Infinity;
}
distances[origin] = 0;
queue.push({ station: origin, distance: 0 });

while (queue.length > 0) {
  queue.sort((a, b) => a.distance - b.distance);
  const current = queue.shift();

  if (visited.has(current.station)) continue;
  visited.add(current.station);

  if (current.station === destination) break;

  const neighbors = graph[current.station] || [];
  for (const neighbor of neighbors) {
    if (visited.has(neighbor.station)) continue;

    const newDistance = distances[current.station] + neighbor.time;

    if (newDistance < distances[neighbor.station]) {
      distances[neighbor.station] = newDistance;
      previous[neighbor.station] = current.station;
      lineUsed[neighbor.station] = neighbor.line;
      queue.push({ station: neighbor.station, distance: newDistance });
    }
  }
}

// Build path
const path = [];
let current = destination;

while (current && current !== origin) {
  path.unshift({ station_id: current, line: lineUsed[current] });
  current = previous[current];
}

if (current === origin) {
  path.unshift({ station_id: origin, line: null });
}

// Station names
const stationMap = {};
for (const s of stations) {
  stationMap[s.station_id] = s.name;
}

const pathWithNames = path.map(p => ({
  station_id: p.station_id,
  station_name: stationMap[p.station_id] || p.station_id,
  line: p.line
}));

const linesUsed = [...new Set(path.map(p => p.line).filter(l => l))];
const totalSeconds = distances[destination];
const totalMinutes = Math.round(totalSeconds / 60);

return {
  user_id: webhookData.user_id,
  origin: origin,
  origin_name: stationMap[origin] || origin,
  destination: destination,
  destination_name: stationMap[destination] || destination,
  route: pathWithNames,
  lines_used: linesUsed,
  total_minutes: totalMinutes,
  total_seconds: totalSeconds,
  delay_predictions: delayPredictions,
  route_calculated_at: new Date().toISOString()
};

const input = $input.first().json;

const userId = input.user_id;
const route = input.route;
const linesUsed = input.lines_used;

// Simulated user history (in real app, fetch from Supabase)
const userHistory = {
  "user_001": { trips: 12, preferred_lines: ["district", "central"], avg_rating: 4.2 },
  "user_002": { trips: 3, preferred_lines: ["northern"], avg_rating: 3.8 },
  "guest_001": { trips: 0, preferred_lines: [], avg_rating: null }
};

const history = userHistory[userId] || { trips: 0, preferred_lines: [], avg_rating: null };
const tripCount = history.trips;

// Decide algorithm
let algorithm;
let recommendation;
let reason;

if (tripCount === 0) {
  // NEW USER: Collaborative Filtering
  algorithm = "collaborative_filtering";
  recommendation = "suggested_route";
  reason = "New user — recommending popular route based on similar commuters";

} else if (tripCount <= 5) {
  // FEW TRIPS: Hybrid approach
  algorithm = "hybrid";
  const epsilon = 0.3;
  const randomValue = Math.random();

  if (randomValue < epsilon) {
    recommendation = "explore_alternative";
    reason = `Exploring! (random ${randomValue.toFixed(2)} < ε ${epsilon}) — try a different route today`;
  } else {
    recommendation = "suggested_route";
    reason = `Exploiting your history (random ${randomValue.toFixed(2)} >= ε ${epsilon}) — using your preferred lines`;
  }

} else {
  // EXPERIENCED USER: Epsilon-Greedy
  algorithm = "epsilon_greedy";
  const epsilon = 0.1;
  const randomValue = Math.random();

  if (randomValue < epsilon) {
    recommendation = "explore_alternative";
    reason = `Exploring! (random ${randomValue.toFixed(2)} < ε ${epsilon}) — you might find a better route`;
  } else {
    recommendation = "suggested_route";
    reason = `Exploiting! (random ${randomValue.toFixed(2)} >= ε ${epsilon}) — sticking with what works for you`;
  }
}

// Check if route uses preferred lines
const usesPreferredLines = linesUsed.some(line => history.preferred_lines.includes(line));

return {
  user_id: userId,
  origin: input.origin,
  origin_name: input.origin_name,
  destination: input.destination,
  destination_name: input.destination_name,
  route: route,
  lines_used: linesUsed,
  total_minutes: input.total_minutes,
  algorithm_used: algorithm,
  recommendation: recommendation,
  reason: reason,
  user_profile: {
    trip_count: tripCount,
    preferred_lines: history.preferred_lines,
    uses_preferred_lines: usesPreferredLines
  },
  delay_predictions: input.delay_predictions,
  learning_applied_at: new Date().toISOString()
};

const input = $input.first().json;

const delayPredictions = input.delay_predictions || {};
const linesUsed = input.lines_used || [];
const userProfile = input.user_profile || {};
const preferredLines = userProfile.preferred_lines || [];

// Combine: lines on current route + user's preferred lines (no duplicates)
const linesToCheck = [...new Set([...linesUsed, ...preferredLines])];

// Check delays only for relevant lines
let alertsSummary = 'None';
const delayedLinesOnRoute = [];
const delayedPreferredLines = [];

for (const line of linesUsed) {
  const prediction = delayPredictions[line];
  if (prediction) {
    if (prediction.is_delayed === 1) {
      delayedLinesOnRoute.push(`${line}: delays reported`);
    } else if (prediction.delay_probability > 0.3) {
      delayedLinesOnRoute.push(`${line}: ${Math.round(prediction.delay_probability * 100)}% delay chance`);
    }
  }
}

// Check preferred lines that are NOT on current route (for heads up)
for (const line of preferredLines) {
  if (!linesUsed.includes(line)) {
    const prediction = delayPredictions[line];
    if (prediction && (prediction.is_delayed === 1 || prediction.delay_probability > 0.3)) {
      delayedPreferredLines.push(`${line}: ${Math.round(prediction.delay_probability * 100)}% delay chance`);
    }
  }
}

// Determine status based on CURRENT ROUTE only
let statusEmoji = '✅';
let statusText = 'All clear — smooth travels!';

if (delayedLinesOnRoute.length > 0) {
  const hasActualDelay = linesUsed.some(line => delayPredictions[line]?.is_delayed === 1);
  if (hasActualDelay) {
    statusEmoji = '⚠️';
    statusText = 'Delays on your route — allow extra time';
  } else {
    statusEmoji = '🟡';
    statusText = 'Minor disruptions possible on your route';
  }
  alertsSummary = delayedLinesOnRoute.join(', ');
} else if (delayedPreferredLines.length > 0) {
  // Route is clear, but preferred lines have issues
  alertsSummary = 'Your route is clear! Heads up: ' + delayedPreferredLines.join(', ');
}

// Build route summary
const routeSummary = input.route.map(r => r.station_name).join(' → ');

// Current time
const now = new Date();

return {
  user_id: input.user_id,
  origin_name: input.origin_name,
  destination_name: input.destination_name,
  route: input.route,
  route_summary: routeSummary,
  lines_used: input.lines_used,
  total_minutes: input.total_minutes,
  status_emoji: statusEmoji,
  status_text: statusText,
  recommendation: input.recommendation,
  reason: input.reason,
  alerts_summary: alertsSummary,
  user_type: userProfile.trip_count === 0 ? 'new' : (userProfile.trip_count <= 5 ? 'learning' : 'experienced'),
  current_time: {
    day: now.toLocaleDateString('en-GB', { weekday: 'long' }),
    date: now.toLocaleDateString('en-GB', { day: 'numeric', month: 'long' }),
    time: now.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' })
  }
};

